mapper.select:
SELECT * FROM sky_take_out.orders


        and status = #{dto.status}


        and phone = #{dto.phone}


        and number = #{dto.number}


        and order_time >= #{dto.beginTime}


        and order_time <= #{dto.endTime}


    and shop_id = #{shopId}




        order by order_time desc


        order by checkout_time desc


        order by delivery_time desc

select date(order_time) as day, count(id) as totalOrderCount
from orders


        and order_time >= #{dto.begintime}


        and order_time < #{dto.endtime}


        and status = #{dto.status}


        and shop_id = #{dto.shopId}


group by date(order_time)
order by day

select od.name as name, sum(od.number) as number
from orders o, order_detail od

    o.id = od.order_id

        and order_time >= #{dto.begintime}


        and order_time < #{dto.endtime}


        and status = #{dto.status}


group by od.name
order by number desc
limit 0,10

select * from orders


        and number like concat('%',#{number},'%')


        and phone like concat('%',#{phone},'%')


        and user_id = #{userId}


        and status = #{status}


        and order_time >= #{beginTime}


        and order_time <= #{endTime}


order by order_time desc
